const rows = $input.all().map(i => i.json);
const conCita = rows.filter(r => r.first_appointment).length;
const sinCita = rows.length - conCita;
return [{ json: {
  summary: { num_nuevos: rows.length, con_cita: conCita, sin_cita: sinCita, tasa_conversion: rows.length ? conCita / rows.length : 0 },
  rows
} }];

const rows = $input.all().map(i => i.json).map(r => ({
  ...r,
  days_inactive: r.days_inactive != null ? Number(r.days_inactive) : null,
  debt_uyu: Number(r.debt_uyu || 0),
  debt_usd: Number(r.debt_usd || 0),
}));

const altaMedica  = rows.filter(r => r.inactivity_reason === 'alta_medica').length;
const inactividad = rows.filter(r => r.inactivity_reason === 'inactividad').length;
const conDeuda    = rows.filter(r =>
  r.inactivity_reason === 'inactividad' && (r.debt_uyu > 0 || r.debt_usd > 0)
).length;

return [{ json: {
  summary: {
    total_inactivos: rows.length,
    alta_medica: altaMedica,
    inactividad: inactividad,
    con_deuda: conDeuda
  },
  rows
} }];

const rows = $input.all().map(i => i.json).map(r => ({
  ...r,
  total_steps:          Number(r.total_steps    || 0),
  done_steps:           Number(r.done_steps     || 0),
  pending_steps:        Number(r.pending_steps  || 0),
  waiting_steps:        Number(r.waiting_steps  || 0),
  alert_steps:          Number(r.alert_steps    || 0),
  days_active:          r.days_active          != null ? Number(r.days_active)          : null,
  days_since_last_step: r.days_since_last_step != null ? Number(r.days_since_last_step) : null,
  steps_detail:         Array.isArray(r.steps_detail) ? r.steps_detail : (r.steps_detail ? JSON.parse(r.steps_detail) : []),
}));

const total           = rows.length;
const completados     = rows.filter(r => r.status === 'completed').length;
const en_curso        = total - completados;
const tasa_completado = total > 0 ? completados / total : 0;
const steps_done      = rows.reduce((s, r) => s + r.done_steps,    0);
const steps_pending   = rows.reduce((s, r) => s + r.pending_steps, 0);
const steps_waiting   = rows.reduce((s, r) => s + r.waiting_steps, 0);
const steps_alert     = rows.reduce((s, r) => s + r.alert_steps,   0);

return [{ json: {
  summary: { total, en_curso, completados, tasa_completado, steps_done, steps_pending, steps_waiting, steps_alert },
  rows
} }];
